SELECT cases.summary, cases.severity_level, case_statuses.status_name
FROM cases
JOIN case_statuses ON cases.status_id = case_statuses.status_id;

SELECT c.summary 
FROM cases AS c
WHERE c.severity_level = 3 AND c.status_id = 1;

SELECT user_id
FROM case_history
WHERE action_time = (
  SELECT MIN(action_time)
  FROM case_history
);

SELECT AVG(severity_level) AS average_severity
FROM cases
WHERE status_id = (SELECT status_id FROM case_statuses WHERE status_name = 'Open');
